static int cuda_available_cached()
{
  static int checked = 0;
  static int available = 0;
  if (!checked) {
    int count = 0;
    cudaError_t err = cudaGetDeviceCount(&count);
    available = (err == cudaSuccess && count > 0) ? 1 : 0;
    checked = 1;
  }
  return available;
}

static float *flatten_matrix(float **w, int rows, int cols)
{
  float *flat = (float *)malloc((size_t)rows * (size_t)cols * sizeof(float));
  if (flat == NULL) return NULL;
  for (int i = 0; i < rows; i++) {
    for (int j = 0; j < cols; j++) {
      flat[i * cols + j] = w[i][j];
    }
  }
  return flat;
}

static void unflatten_matrix(float **w, const float *flat, int rows, int cols)
{
  for (int i = 0; i < rows; i++) {
    for (int j = 0; j < cols; j++) {
      w[i][j] = flat[i * cols + j];
    }
  }
}

static void bpnn_layerforward_cpu(float *l1, float *l2, float **conn, int n1, int n2)
{
  l1[0] = 1.0f;
  for (int j = 1; j <= n2; j++) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = 1.0f / (1.0f + expf(-sum));
  }
}

static void bpnn_adjust_weights_cpu(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  ly[0] = 1.0f;
  for (int j = 1; j <= ndelta; j++) {
    for (int k = 0; k <= nly; k++) {
      float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

__device__ static float squash_device(float x)
{
  return 1.0f / (1.0f + expf(-x));
}

__global__ static void layerforward_kernel(const float *l1, float *l2, const float *conn, int n1, int n2)
