extern "C" void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  if (!cuda_available_cached()) {
    bpnn_layerforward_cpu(l1, l2, conn, n1, n2);
    return;
  }

  l1[0] = 1.0f;

  int rows = n1 + 1;
  int cols = n2 + 1;
  size_t l1_size = (size_t)rows * sizeof(float);
  size_t l2_size = (size_t)cols * sizeof(float);
  size_t conn_size = (size_t)rows * (size_t)cols * sizeof(float);

  float *h_conn = flatten_matrix(conn, rows, cols);
  if (h_conn == NULL) {
    bpnn_layerforward_cpu(l1, l2, conn, n1, n2);
    return;
  }

  float *d_l1 = NULL, *d_l2 = NULL, *d_conn = NULL;
  bool ok = true;

  if (cudaMalloc((void **)&d_l1, l1_size) != cudaSuccess) ok = false;
  if (ok && cudaMalloc((void **)&d_l2, l2_size) != cudaSuccess) ok = false;
  if (ok && cudaMalloc((void **)&d_conn, conn_size) != cudaSuccess) ok = false;
  if (ok && cudaMemcpy(d_l1, l1, l1_size, cudaMemcpyHostToDevice) != cudaSuccess) ok = false;
  if (ok && cudaMemcpy(d_l2, l2, l2_size, cudaMemcpyHostToDevice) != cudaSuccess) ok = false;
  if (ok && cudaMemcpy(d_conn, h_conn, conn_size, cudaMemcpyHostToDevice) != cudaSuccess) ok = false;

  if (ok) {
    int block = 256;
    int grid = (n2 + block - 1) / block;
    layerforward_kernel<<<grid, block>>>(d_l1, d_l2, d_conn, n1, n2);
    if (cudaGetLastError() != cudaSuccess) ok = false;
    if (ok && cudaDeviceSynchronize() != cudaSuccess) ok = false;
    if (ok && cudaMemcpy(l2, d_l2, l2_size, cudaMemcpyDeviceToHost) != cudaSuccess) ok = false;
  }

  if (d_l1) cudaFree(d_l1);
  if (d_l2) cudaFree(d_l2);
  if (d_conn) cudaFree(d_conn);
  free(h_conn);

  if (!ok) {
    bpnn_layerforward_cpu(l1, l2, conn, n1, n2);
  }
}

extern "C" void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)
{
  int j;
  float o, t, errsum;
  errsum = 0.0f;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

extern "C" void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err)
{
  int j, k;
  float h, sum, errsum;

  errsum = 0.0f;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0f;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

extern "C" void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  if (!cuda_available_cached()) {
    bpnn_adjust_weights_cpu(delta, ndelta, ly, nly, w, oldw);
    return;
  }

  ly[0] = 1.0f;

  int rows = nly + 1;
  int cols = ndelta + 1;

  size_t delta_size = (size_t)(ndelta + 1) * sizeof(float);
  size_t ly_size = (size_t)(nly + 1) * sizeof(float);
  size_t matrix_size = (size_t)rows * (size_t)cols * sizeof(float);

  float *h_w = flatten_matrix(w, rows, cols);
  float *h_oldw = flatten_matrix(oldw, rows, cols);
  if (h_w == NULL || h_oldw == NULL) {
    if (h_w) free(h_w);
    if (h_oldw) free(h_oldw);
    bpnn_adjust_weights_cpu(delta, ndelta, ly, nly, w, oldw);
    return;
  }

  float *d_delta = NULL, *d_ly = NULL, *d_w = NULL, *d_oldw = NULL;
  bool ok = true;

  if (cudaMalloc((void **)&d_delta, delta_size) != cudaSuccess) ok = false;
  if (ok && cudaMalloc((void **)&d_ly, ly_size) != cudaSuccess) ok = false;
  if (ok && cudaMalloc((void **)&d_w, matrix_size) != cudaSuccess) ok = false;
  if (ok && cudaMalloc((void **)&d_oldw, matrix_size) != cudaSuccess) ok = false;

  if (ok && cudaMemcpy(d_delta, delta, delta_size, cudaMemcpyHostToDevice) != cudaSuccess) ok = false;
  if (ok && cudaMemcpy(d_ly, ly, ly_size, cudaMemcpyHostToDevice) != cudaSuccess) ok = false;
  if (ok && cudaMemcpy(d_w, h_w, matrix_size, cudaMemcpyHostToDevice) != cudaSuccess) ok = false;
  if (ok && cudaMemcpy(d_oldw, h_oldw, matrix_size, cudaMemcpyHostToDevice) != cudaSuccess) ok = false;

  if (ok) {
    int total = ndelta * (nly + 1);
    int block = 256;
    int grid = (total + block - 1) / block;
    adjust_weights_kernel<<<grid, block>>>(d_delta, ndelta, d_ly, nly, d_w, d_oldw);
    if (cudaGetLastError() != cudaSuccess) ok = false;
    if (ok && cudaDeviceSynchronize() != cudaSuccess) ok = false;
    if (ok && cudaMemcpy(h_w, d_w, matrix_size, cudaMemcpyDeviceToHost) != cudaSuccess) ok = false;
    if (ok && cudaMemcpy(h_oldw, d_oldw, matrix_size, cudaMemcpyDeviceToHost) != cudaSuccess) ok = false;
  }

  if (d_delta) cudaFree(d_delta);
  if (d_ly) cudaFree(d_ly);
  if (d_w) cudaFree(d_w);
  if (d_oldw) cudaFree(d_oldw);

  if (!ok) {
    free(h_w);
    free(h_oldw);
    bpnn_adjust_weights_cpu(delta, ndelta, ly, nly, w, oldw);
    return;
  }

  unflatten_matrix(w, h_w, rows, cols);
  unflatten_matrix(oldw, h_oldw, rows, cols);
  free(h_w);
  free(h_oldw);
}

extern "C" void bpnn_feedforward(BPNN *net)
{
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

extern "C" void bpnn_train(BPNN *net, float *eo, float *eh)
{
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;
  float out_err, hid_err;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out,
                    net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid,
                      net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in,
                      net->input_weights, net->input_prev_weights);
}

